code_changes.new_string:
fn query_container_size(
    &self,
    _display: &Display,
) -> euclid::default::Size2D<Option<app_units::Au>> {
    // Container queries require layout information which is not available during style computation.
    // Return None for both dimensions, which will cause container queries to fall back to viewport size.
